import aiocoap as coap

# Define the resources to be exposed via CoAP
resources = {
    "/sensors/temp": {"type": "temperature", "value": 25},
    "/actuators/light": {"type": "light", "value": False}
}

# Create a CoAP server and start listening for requests
server = coap.Server()
server.listen(("0.0.0.0", 5683))

# Define the callback function to handle incoming requests
def handle_request(request):
    # Extract the requested resource from the request
    resource = request.path[1:]

    # Check if the requested resource is valid and exists in our resources dictionary
    if resource not in resources:
        return coap.Response(code=coap.Code.NOT_FOUND)

    # Handle GET requests for the requested resource
    if request.method == "GET":
        return coap.Response(payload=resources[resource]["value"])

    # Handle PUT requests for the requested resource
    elif request.method == "PUT":
        # Validate the input data and update the resource value accordingly
        try:
            new_value = float(request.payload)
            resources[resource]["value"] = new_value
            return coap.Response(code=coap.Code.CHANGED)
        except ValueError:
            return coap.Response(code=coap.Code.BAD_REQUEST)

    # Handle any other request methods as not supported
    else:
        return coap.Response(code=coap.Code.METHOD_NOT_ALLOWED)

# Start the CoAP server and handle incoming requests
server.start(handle_request)